VALUES
  ('social-worker-moex-03860', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者屬於社區取向的社會工作原則？', '["專業責任的原則", "責任分擔的原則", "農村扶貧的原則", "個別差異的原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03861', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體領導技巧的敘述，下列何者正確？', '["團體工作者為維持領導功能與權力，應減少在團體中進行自我揭露", "摘要的技術是指工作者針對成員發送的口語或非口語訊息予以映照的技術，以傳達工作者對成 員談話內容與背後感覺的了解", "團體成員出現不適當的行為舉止時，團體工作者可以適時使用阻斷技巧加以規範", "團體成員每次自我揭露以後，都要運用摘要技巧，讓成員感到被重視、被了解"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03862', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「團體領導者的個人價值觀對團體的影響」的敘述，下列何者錯誤？', '["個人若能覺察到自己所抱持的價值觀，以及價值觀可能會直接或是間接影響團體成員，將可以 成為一位更有效能的領導者", "團體成員會尋求幫助，通常是因為他們面臨價值上的衝突，因此這些人也最容易受到團體領導 者的左右，也常易因權威者的影響而受到傷害", "團體領導者期待團體成員接受領導者個人的價值觀，即傳達了成員沒有機會去探索另一套有意 義的價值觀", "團體工作者的價值觀與團體成員、協同工作者或機構的價值觀有很大的差異時，將無法進行有 效的團體工作"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03863', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作實施倫理中告知暨徵求同意（informedconsent）的內涵，下列何者正確？①中途退', '["團體成員可隨時中止錄音或錄影", "團體的目的", "團體成員的 招募與篩選過程", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03864', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作紀錄、錄音或錄影檔案運用之倫理，下列何者正確？', '["經團體領導者同意，團體工作紀錄即可提供其他人作為研究之用，錄音及錄音檔案則需要團體 成員同意", "因評鑑需要，評鑑委員有權自行調閱團體工作紀錄，為保密原則之例外，不一定要簽署保密同 意書", "因督導工作的需要，督導者觀看團體過程的錄影檔案，需要取得團體成員告知同意", "因社工教育需要，實習生可以在機構內閱讀去除個人身分資訊之團體工作紀錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03865', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關虛擬社區（virtualcommunity）的特質，下列何者錯誤？', '["表達的自由", "多對多的傳播", "集中的控制", "成員出自於自願的行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03866', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關睦鄰運動的敘述，下列何者錯誤？', '["探討社區工作的起源時，常以英國湯恩比館的睦鄰運動為起點", "睦鄰運動承襲慈善組織會社及基督社會主義的理念，認為解決貧窮的問題需要科學調查，並透 過教育開拓窮人的生活", "睦鄰運動被歸納為家戶長思想，在於其以上層階級與中產階級為中心，對貧民與下層階級的生 活指導", "湯恩比館對社區工作的重要啟示，在於制定固定的工作計畫、標準化工作內容，提供社區發展 所需要的服務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03867', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於學者Rothman提出的地方發展模式，因強調自助的特性而產生的限制，下列何者錯誤？', '["強調地方發展，與全國性發展或區域發展不易發生衝突", "窮的社區一定越窮，自助能力不足，資源分配不均", "全球化的影響，自助的力量越來越不足", "並非所有的社區都有自由結社的權利，如集權社會，自助可能性就會降低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03868', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區行動模式中，引發社區衝突的原因有很多，下列何者錯誤？', '["社區的同質性", "既存的分裂", "領導者的無能、偏頗", "社區積累的不滿情緒已到難以容忍的地步"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03869', 'social-worker', 'social-worker-moex-112-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於立基於資產的社區發展模式中，所面對的挑戰，下列何者錯誤？', '["外部專家僅在初始階段扮演促進者的角色，且不斷擴大資產連結的功能，但仍難以避免誘發依賴", "這是一種包容性的過程，但仍會面臨社區中存在的等級、社經地位的差異或社會排除群體的情況", "資產是社區驅動的主力，因此領導者有無能力加以有效運作，非為核心問題", "外部環境條件不可忽略，外部環境將影響社區實現其潛力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:22+00:00", "source_pdf_sha1": "b579889576bc", "answer_pdf_sha1": "1ccce4f000cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
